('SOUND Behavioral Health', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Community behavioral health agency offering addiction treatment assessments and outpatient alcohol/drug treatment for youth and adults, individual/couple/family/group mental health counseling, and integrated treatment for co-occurring disorders. Multiple Seattle-area locations.', '1600 E Olive Street', 'Seattle', 'King', 'WA', '98122', '(206) 302-2300', 'https://www.sound.health', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community behavioral health agency offering addiction treatment assessments and outpatient alcohol/drug treatment for youth and adults,individual/couple/family/group mental health counseling,and integrated treatment for co-occurring disorders,Multiple Seattle-area locations}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
