('Asian Counseling and Referral Service (ACRS)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Behavioral health and human services organization serving the Asian and Pacific Islander community. Services include mental health counseling, substance use disorder treatment, aging and long-term care, employment services, food bank, and citizenship assistance. TTY: (800) 833-6384.', '3639 Martin Luther King Jr. Way South', 'Seattle', 'King', 'WA', '98144', '(206) 695-7600', 'https://acrs.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Behavioral health and human services organization serving the Asian and Pacific Islander community,Services include mental health counseling,substance use disorder treatment,aging and long-term care,employment services}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Seattle Counseling Service', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Founded in 1969, the oldest mental health agency in the United States focused on the LGBTQ+ community. Licensed community mental health agency providing counseling, therapy, and general wellness services to LGBTQ+ individuals.', '2033 6th Avenue, Suite 400', 'Seattle', 'King', 'WA', '98121', '(206) 323-1768', 'https://seattlecounseling.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1969,the oldest mental health agency in the United States focused on the LGBTQ+ community,Licensed community mental health agency providing counseling,therapy,and general wellness services to LGBTQ+ individuals}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
